import{_ as a,o as c,c as d,a2 as o}from"./chunks/framework.BKG_UbFK.js";const f=JSON.parse('{"title":"安全性","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/security.md","filePath":"zh/guide/security.md"}'),r={name:"zh/guide/security.md"};function t(l,e,i,s,n,h){return c(),d("div",null,[...e[0]||(e[0]=[o('<h1 id="安全性" tabindex="-1">安全性 <a class="header-anchor" href="#安全性" aria-label="Permalink to &quot;安全性&quot;">​</a></h1><p>Clearance 在发布前经历了一次专门的安全审计，以及此后的两轮加固。要点包括：在每一条授予权限的路径上（无论是直接授权还是角色级同步）都设有权限提升上限、拒绝优先的上下文覆盖机制、一个采用白名单策略的 SVG 净化器、一个受保护的 <code>clearance-*</code> 权限命名空间，以及对访客安全的 Blade 指令。</p><h2 id="面板访问与精细化的写权限" tabindex="-1">面板访问与精细化的写权限 <a class="header-anchor" href="#面板访问与精细化的写权限" aria-label="Permalink to &quot;面板访问与精细化的写权限&quot;">​</a></h2><p>对整个面板的读访问需要 <code>clearance-access</code> 权限（通过 <code>can()</code> 检查，绝不通过 <code>hasRole()</code>）。每个分区的写操作都由一个专属的、可委派的权限控制——全部由 <code>clearance:install</code> 创建并分配给 <code>super_admin</code>：</p><table tabindex="0"><thead><tr><th>权限</th><th>控制内容</th></tr></thead><tbody><tr><td><code>clearance-permissions-write</code></td><td>创建/编辑/删除权限</td></tr><tr><td><code>clearance-roles-write</code></td><td>创建/编辑/删除角色及其权限分配</td></tr><tr><td><code>clearance-guards-write</code></td><td>创建/编辑/删除看守器</td></tr><tr><td><code>clearance-settings-write</code></td><td>编辑显示元数据、图标、颜色、默认角色</td></tr><tr><td><code>clearance-users-write</code></td><td>为特定用户分配/移除角色</td></tr></tbody></table><p>如果某个精细化权限记录在数据库中完全不存在（一种历史遗留的、未预置的状态），检查会回退到 <code>clearance-access</code>，以保持向后兼容。</p><h2 id="受保护的-clearance-命名空间" tabindex="-1">受保护的 <code>clearance-*</code> 命名空间 <a class="header-anchor" href="#受保护的-clearance-命名空间" aria-label="Permalink to &quot;受保护的 `clearance-*` 命名空间&quot;">​</a></h2><p><code>clearance-*</code> 权限是被保留的：除了通过该包自身的安装流程之外，任何人都无法创建、重命名、删除它们，也无法将其添加到任何角色——即使是 <code>super_admin</code> 本身的操作者，针对 <code>super_admin</code> 角色本身也不例外。</p><h2 id="权限提升上限" tabindex="-1">权限提升上限 <a class="header-anchor" href="#权限提升上限" aria-label="Permalink to &quot;权限提升上限&quot;">​</a></h2><p>Clearance 中每一条授予权限的路径都强制执行一个上限，使得操作者永远无法授予超出自己所持有的权限：</p><ul><li><strong>上限角色</strong>——一个角色可以声明一个父角色，其权限集合作为上限。任何超出的权限都会在 <code>RoleService::setParent()</code> 以及此后每一次权限同步时被默默裁剪——没有异常，也没有错误提示。从父角色移除权限会自动级联到每一个子角色。完整的上限 API 请参见<a href="/clearance-docs/zh/features/roles.html">角色</a>。</li><li><strong>用户模块</strong>——角色分配以及直接/覆盖式的权限授予都强制执行一个权限提升上限：非 <code>super_admin</code> 的操作者无法修改自己的分配，也无法授予自己都不持有的权限。参见<a href="/clearance-docs/zh/features/users.html">用户</a>。</li></ul><h2 id="拒绝优先的上下文覆盖" tabindex="-1">拒绝优先的上下文覆盖 <a class="header-anchor" href="#拒绝优先的上下文覆盖" aria-label="Permalink to &quot;拒绝优先的上下文覆盖&quot;">​</a></h2><p>按上下文的权限覆盖（<code>clr_ctx_overrides</code>）支持 <code>forced_on</code> 和 <code>forced_off</code>。<code>forced_off</code> 始终优先生效——即使是由全局角色授予的权限也不例外。没有任何路径能让一个优先级更低的授权覆盖一个明确的拒绝。完整的解析顺序请参见<a href="/clearance-docs/zh/guide/architecture.html#解析机制">架构</a>。</p><h2 id="svg-净化" tabindex="-1">SVG 净化 <a class="header-anchor" href="#svg-净化" aria-label="Permalink to &quot;SVG 净化&quot;">​</a></h2><p>每一个用户提供的图标（设置面板中的角色/看守器显示元数据）在存储前以及每次渲染时都会经过一个白名单净化器处理——而不仅仅是上传时的一次性检查。</p><h2 id="对访客安全的-blade-指令" tabindex="-1">对访客安全的 Blade 指令 <a class="header-anchor" href="#对访客安全的-blade-指令" aria-label="Permalink to &quot;对访客安全的 Blade 指令&quot;">​</a></h2><p><code>@canin</code> 和 <code>@hasrolein</code> 对访客用户都会安全地解析（返回 <code>false</code>）——它们从不抛出异常。</p><h2 id="gate-绕过是应用范围内的" tabindex="-1">Gate 绕过是应用范围内的 <a class="header-anchor" href="#gate-绕过是应用范围内的" aria-label="Permalink to &quot;Gate 绕过是应用范围内的&quot;">​</a></h2><p><code>super_admin_gate_bypass</code>（默认 <code>false</code>）控制 <code>super_admin</code> 角色是否通过一个 <code>Gate::before()</code> 钩子，在全局范围内绕过所有 Laravel 的 <code>can()</code>/<code>Gate::allows()</code>/策略检查。</p><div class="warning custom-block"><p class="custom-block-title">并非仅限于面板范围</p><p>启用后，任何持有 <code>super_admin</code> 的用户都会跳过整个应用范围内的所有 Gate 检查——不仅仅是 Clearance 面板的检查。请谨慎地有意启用它。别名检测与提升行为请参见<a href="/clearance-docs/zh/features/super-admin.html">超级管理员</a>。</p></div><h2 id="与安全相关的注意事项" tabindex="-1">与安全相关的注意事项 <a class="header-anchor" href="#与安全相关的注意事项" aria-label="Permalink to &quot;与安全相关的注意事项&quot;">​</a></h2><ul><li><code>forced_off</code> 始终优先生效——即使是由全局角色授予的权限也不例外。</li><li>上限角色只会裁剪权限，从不授予权限——设置一个权限宽松的父角色本身不会给子角色带来任何权限。</li><li>Gate 绕过（<code>super_admin_gate_bypass</code>）是应用范围内的，而非仅限于面板范围。</li><li>用户模块默认关闭（<code>modules.users = false</code>）。</li><li><code>clearance-*</code> 权限在安装流程之外是不可触碰的，即使对 <code>super_admin</code> 也是如此。</li><li>在全新环境中，请始终运行 <code>clearance:install</code>，而不是直接运行 <code>migrate</code>——参见<a href="/clearance-docs/zh/guide/installation.html">安装</a>。</li></ul><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="/clearance-docs/zh/guide/architecture.html">架构</a>——解析优先级与 <code>clr_*</code> 表结构</li><li><a href="/clearance-docs/zh/features/roles.html">角色</a>——深入了解上限角色</li><li><a href="/clearance-docs/zh/features/users.html">用户</a>——角色/权限分配上的权限提升上限</li><li><a href="/clearance-docs/zh/features/super-admin.html">超级管理员</a>——Gate 绕过与别名检测</li></ul>',24)])])}const p=a(r,[["render",t]]);export{f as __pageData,p as default};
